const tasksRaw = $('Fetch TASKS.md').first().json.data || JSON.stringify($('Fetch TASKS.md').first().json);
const knowledgeRaw = $('Fetch KNOWLEDGE.md').first().json.data || JSON.stringify($('Fetch KNOWLEDGE.md').first().json);

// Trim TASKS.md: keep header + Front-and-Center + active phases only
const tasksLines = String(tasksRaw).split('\n');
const trimmedTasks = [];
let keep = true;
let headerDone = false;
for (const line of tasksLines) {
  if (line.startsWith('## Phase') || line.startsWith('## Section')) {
    headerDone = true;
    const isDone = /COMPLETE|completed|100%/i.test(line);
    keep = !isDone;
  }
  if (!headerDone || keep) trimmedTasks.push(line);
}
const tasks = trimmedTasks.join('\n').slice(0, 12000);

// Trim KNOWLEDGE.md: keep Front-and-Center section + last 15 decision entries
const kLines = String(knowledgeRaw).split('\n');
const frontAndCenter = [];
let inFAC = false;
for (const line of kLines) {
  if (/^#.*Front.and.Center/i.test(line)) inFAC = true;
  if (inFAC) {
    frontAndCenter.push(line);
    if (frontAndCenter.length > 1 && /^---/.test(line)) break;
  }
}
const decisionBlocks = String(knowledgeRaw).split(/(?=^### D\d+)/m);
const recentDecisions = decisionBlocks.slice(-15).join('\n');
const knowledge = (frontAndCenter.join('\n') + '\n\n--- Recent Decisions ---\n' + recentDecisions).slice(0, 8000);

let vmpSummary = '';
try {
  const ghToken = $env.GITHUB_TOKEN || '';
  const headers = { Accept: 'application/vnd.github.v3.raw', 'User-Agent': 'n8n-paperwork' };
  if (ghToken) headers.Authorization = `Bearer ${ghToken}`;
  vmpSummary = await this.helpers.httpRequest({ method: 'GET', url: 'https://api.github.com/repos/paperwork-labs/paperwork/contents/docs/VMP-SUMMARY.md', headers });
  if (typeof vmpSummary !== 'string') vmpSummary = JSON.stringify(vmpSummary);
  vmpSummary = vmpSummary.slice(0, 4000);
} catch (e) { vmpSummary = '[VMP-SUMMARY.md not available]'; }

let infraHealth = '';
try {
  const apiKey = $env.N8N_API_KEY;
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: 'http://localhost:5678/api/v1/workflows?limit=250',
    headers: { 'X-N8N-API-KEY': apiKey },
  });
  const workflows = resp.data || [];
  const total = workflows.length;
  const active = workflows.filter(w => w.active).length;
  infraHealth = `n8n workflows: ${active}/${total} active`;
  if (active < total) {
    const inactiveNames = workflows.filter(w => !w.active).map(w => w.name).join(', ');
    infraHealth += `\nInactive: ${inactiveNames}`;
  }
} catch (e) { infraHealth = 'Could not check n8n health'; }

return [{ json: { tasks, knowledge, vmpSummary, infraHealth } }];

function sanitizeSlackMrkdwn(text) {
  return String(text || '')
    .replace(/```\w*\n?/g, '```')
    .replace(/^#{1,6}\s+(.+)$/gm, '*$1*')
    .replace(/^[-*_]{3,}\s*$/gm, '')
    .replace(/\*\*(.+?)\*\*/g, '*$1*')
    .replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<$2|$1>')
    .replace(/\n{3,}/g, '\n\n');
}

const output = $json.output || [];
const aiText = (output[0]?.content || []).find(c => c.type === 'output_text')?.text || '';
const date = new Date().toISOString().split('T')[0];
const header = '*Daily Briefing — ' + date + '*\n\n';
const footer = '\n\n_Thread router: reply with a persona name for a focused take._';
const fallback = ':warning: No output generated. Check workflow logs.';
const body = aiText.trim() ? aiText.trim() : fallback;
return [{ json: { text: sanitizeSlackMrkdwn(header + body + footer) } }];
